// ① SoundPlayer 定義
const SoundPlayer = {
  ctx: null,
  buffers: {},
  ready: {},

  async init() {
    if (!this.ctx) {
      this.ctx = new (window.AudioContext || window.webkitAudioContext)();
    }
    if (this.ctx.state !== "running") {
      await this.ctx.resume();
    }
  },

  async load(name, base64) {
    await this.init();

    if (this.ready[name]) return this.ready[name];

    this.ready[name] = (async () => {
      const binary = atob(base64);
      const len = binary.length;
      const buffer = new Uint8Array(len);

      for (let i = 0; i < len; i++) {
        buffer[i] = binary.charCodeAt(i);
      }

      this.buffers[name] =
        await this.ctx.decodeAudioData(buffer.buffer);
    })();

    return this.ready[name];
  },

  async play(name) {
    await this.init();
    await this.ready[name];

    const buf = this.buffers[name];
    if (!buf) return;

    const source = this.ctx.createBufferSource();
    source.buffer = buf;
    source.connect(this.ctx.destination);
    source.start(0);
  }
};
const base64_wav_0 = "";
const base64_wav_1 = "";
const base64_wav_2 = ""
const base64_wav_3 = "";
const base64_wav_4 = "";
const base64_wav_5 = "";
const base64_wav_6 = "";
const base64_wav_7 = "";
const base64_wav_8 = "";
const base64_wav_9 = "";

// ③ 初期ロード
(async () => {
  await SoundPlayer.load("sound0", base64_wav_0);
  await SoundPlayer.load("sound1", base64_wav_1);
  await SoundPlayer.load("sound2", base64_wav_2);
  await SoundPlayer.load("sound3", base64_wav_3);
  await SoundPlayer.load("sound4", base64_wav_4);
  await SoundPlayer.load("sound5", base64_wav_5);
  await SoundPlayer.load("sound6", base64_wav_6);
  await SoundPlayer.load("sound7", base64_wav_7);
  await SoundPlayer.load("sound8", base64_wav_8);
  await SoundPlayer.load("sound9", base64_wav_9);
})();


// ④ 再生関数
function wav(no) {
  if (no == "0") {SoundPlayer.play("sound0")}
  else if (no == "1") {SoundPlayer.play("sound1")}
  else if (no == "2") {SoundPlayer.play("sound2")}
  else if (no == "3") {SoundPlayer.play("sound3")}
  else if (no == "4") {SoundPlayer.play("sound4")}
  else if (no == "5") {SoundPlayer.play("sound5")}
  else if (no == "6") {SoundPlayer.play("sound6")}
  else if (no == "7") {SoundPlayer.play("sound7")}
  else if (no == "8") {SoundPlayer.play("sound8")}
  else if (no == "9") {SoundPlayer.play("sound9")}
	
}
